  )
  qseries <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-support-cells.tsv"
  )

  expect_named(
    contract,
    c(
      "contract_id",
      "cell_id",
      "provider",
      "source_row_selection_id",
      "source_smoke_contract_id",
