      "current_denominator_action",
      "pregrid_min_replicates",
      "seed_policy",
      "failed_profile_retention",
      "nonconverged_fit_retention",
      "nonfinite_interval_retention",
      "bootstrap_refit_retention",
      "mcse_threshold",
      "coverage_evaluable",
      "coverage_status",
      "interval_claim_status",
      "status",
