    stringsAsFactors = FALSE
  )
  run_log <- utils::read.delim(
    structured_re_artifact_path(
      "docs",
      "dev-log",
      "simulation-artifacts",
      "2026-06-25-pr-stack-merge-readiness",
      "structured-re-pr-stack-merge-readiness-run-log.tsv"
    ),
    sep = "\t",
    quote = "",
    check.names = FALSE,
    stringsAsFactors = FALSE
  )

  expect_named(
    stack,
    c(
      "stack_row_id",
      "merge_order",
      "pr_number",
      "title",
      "base_ref",
      "head_ref",
      "head_sha",
