  )
  artifact <- utils::read.delim(
    structured_re_artifact_path(
      "docs",
      "dev-log",
      "simulation-artifacts",
      "2026-06-29-q4-animal-all-four-admission-probe-nibi",
      "structured-re-q4-animal-all-four-admission-probe-replicates.tsv"
