      "n_rep",
      "n_direct_targets",
      "n_target_rep_rows",
      "n_fit_ok",
      "n_pdhess",
      "pdhess_rate",
      "n_wald_finite",
      "wald_finite_rate",
      "n_profile_attempted",
      "n_profile_finite",
      "profile_finite_rate",
      "n_profile_nonfinite",
      "admission_status",
      "interval_claim_status",
      "coverage_status",
      "status",
      "source_artifact",
      "evidence_url",
      "claim_boundary",
      "next_gate"
