    "gradient_gate",
    "profile_warning_gate",
    "boundary_gate",
    "finite_direct_sd_interval_gate",
    "derived_correlation_interval_gate"
  )) {
    expect_false(any(is.na(contract[[field]]) | contract[[field]] == ""))
  }
  known_evidence_prefix <- grepl(
    "^docs/dev-log/dashboard/",
